from vex_sdk import Vex
from haystack import component

@component
class VexContextGuard:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")

    @component.output_types(documents=list)
    def run(self, query: str, documents: list):
        results = self.vex.verify({
            "type": "context_relevance",
            "query": query,
            "documents": [d.content for d in documents],
            "threshold": 0.7
        })
        filtered = [d for i, d in enumerate(documents) if results["scores"][i] > 0.7]
        return {"documents": filtered}

query_pipe.add_component("vex_guard", VexContextGuard())
query_pipe.connect("retriever.documents", "vex_guard.documents")
query_pipe.connect("vex_guard.documents", "prompt_builder.documents")

query_pipe.add_component("vex_faithfulness", VexFaithfulnessGuard())
query_pipe.connect("generator.replies", "vex_faithfulness.replies")
query_pipe.connect("prompt_builder.documents", "vex_faithfulness.documents")

@component
class VexFaithfulnessGuard:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")

    @component.output_types(replies=list)
    def run(self, replies: list, documents: list):
        verdict = self.vex.verify({
            "type": "source_faithfulness",
            "response": replies[0].content,
            "sources": [d.content for d in documents]
        })
        if verdict["passed"]:
            return {"replies": replies}
        raise ValueError("Faithfulness check failed")

from vex_sdk import VexTrace

class TracedGenerator(OpenAIChatGenerator):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.vex = Vex(api_key="your-vex-key")
        self.trace = VexTrace("rag-pipeline")

    def _generate(self, prompt, **kwargs):
        response = super()._generate(prompt, **kwargs)
        trace_id = self.trace.start(
            inputs={"prompt": prompt},
            metadata=kwargs.get("metadata", {})
        )
        citation_check = self.vex.verify({
            "type": "citation_accuracy",
            "response": response.content,
            "citations": response.meta.get("citations", [])
        })
        self.trace.end(trace_id, {"citations_valid": citation_check["passed"]})
        return response

query_pipe.add_component("generator", TracedGenerator(api_key="your-key"))
